const items = [];

for (const item of $input.all()) {
  let text = item.json.output?.[0]?.content?.[0]?.text 
    || item.json.message?.content 
    || item.json.text 
    || JSON.stringify(item.json);

  text = text.replace(/```json/g, '').replace(/```/g, '').trim();

  const rec = JSON.parse(text);

  items.push({
    json: {
      user_id: rec.user_id,
      risk_level: rec.risk_level,
      urgency: rec.urgency,
      recommendation: rec.recommendation,
      reasoning: rec.reasoning
    }
  });
}

return items;

const users = $input.all();
const total = users.length;

// Contar por risk_level
const counts = {};
for (const item of users) {
  const risk = item.json.risk_level;
  counts[risk] = (counts[risk] || 0) + 1;
}

const today = new Date().toLocaleDateString('es-CO', { 
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' 
});

const html = `
<div style="font-family: Arial, sans-serif; max-width: 500px; margin: 0 auto;">
  <div style="background: #d32f2f; color: white; padding: 20px; border-radius: 8px 8px 0 0; text-align: center;">
    <h1 style="margin: 0; font-size: 20px;">⚠️ Alerta de Churn</h1>
    <p style="margin: 8px 0 0; opacity: 0.9; font-size: 14px;">${today}</p>
  </div>

  <div style="padding: 24px; background: #fff; border: 1px solid #ddd;">
    <p style="color: #333; margin: 0 0 16px; font-size: 15px;">Se identificaron <strong>${total} cliente${total > 1 ? 's' : ''}</strong> que requieren contacto inmediato:</p>

    <table style="width: 100%; border-collapse: collapse;">
      <thead>
        <tr style="background: #f5f5f5;">
          <th style="padding: 10px; text-align: left; font-size: 14px;">Riesgo</th>
          <th style="padding: 10px; text-align: right; font-size: 14px;">Cantidad</th>
        </tr>
      </thead>
      <tbody>
        ${counts['alto'] ? `<tr style="border-bottom: 1px solid #eee;"><td style="padding: 10px; color: #d32f2f; font-weight: bold;">🔴 Alto</td><td style="padding: 10px; text-align: right; font-weight: bold;">${counts['alto']}</td></tr>` : ''}
        ${counts['medio'] ? `<tr style="border-bottom: 1px solid #eee;"><td style="padding: 10px; color: #f57c00; font-weight: bold;">🟡 Medio</td><td style="padding: 10px; text-align: right; font-weight: bold;">${counts['medio']}</td></tr>` : ''}
        ${counts['bajo'] ? `<tr><td style="padding: 10px; color: #388e3c; font-weight: bold;">🟢 Bajo</td><td style="padding: 10px; text-align: right; font-weight: bold;">${counts['bajo']}</td></tr>` : ''}
      </tbody>
    </table>

    <div style="text-align: center; margin-top: 24px;">
      <a href="https://alegra.somoscolombiatech.shop/alerts-cs" 
         style="display: inline-block; background: #7c3aed; color: white; padding: 12px 32px; border-radius: 6px; text-decoration: none; font-weight: bold; font-size: 15px;">
        Ver detalle en la plataforma
      </a>
    </div>
  </div>

  <div style="padding: 12px; background: #f9f9f9; border-radius: 0 0 8px 8px; border: 1px solid #ddd; border-top: none; text-align: center;">
    <p style="margin: 0; font-size: 11px; color: #999;">Alegra CS Analytics — Generado automáticamente</p>
  </div>
</div>`;

return [{ json: { html } }];
